Use this BT. AT GENERATION TIME, the worker MUST read the prior BT's $llm.selected list (or the click targets from Mac's btlog of the prior execution) and embed them into the send_to_llm context as a 'FORBIDDEN PRIOR ANSWERS' list. Without that, the LLM re-picks the same.
```json
{
  "type": "sequence",
  "children": [
    {
      "type": "action",
      "action": "find_and_click",
      "params": {
        "target": "Try again",
        "role": "AXButton",
        "strategy": "mouse_click",
        "match_mode": "exact",
        "post_delay": 1.5
      }
    },
    {
      "type": "action",
      "action": "extract_question",
      "params": {
        "question": {
          "role": "AXStaticText",
          "min_length": 20
        },
        "options": {
          "role": "AXCheckBox",
          "exclude_titles": [
            "Draw on exercise"
          ]
        }
      },
      "store": "q"
    },
    {
      "type": "action",
      "action": "find_all",
      "params": {
        "role": "AXCheckBox"
      },
      "store": "all_boxes"
    },
    {
      "type": "action",
      "action": "send_to_llm",
      "params": {
        "question": "$q.question_text",
        "question_type": "solve_complex",
        "options": "$q.options",
        "context": "RETRY ATTEMPT \u2014 PRIOR ANSWER WAS WRONG. The previously-submitted answers were marked WRONG by Khan. The worker generating this BT should populate this context with the EXACT options previously selected so the LLM does NOT pick the same combination. Format: 'FORBIDDEN PRIOR ANSWERS (do not pick these): (Choice X) ..., (Choice Y) ...'. Then the LLM picks from the REMAINING options. Use the screenshot to re-examine each option's diagram/text."
      },
      "store": "llm"
    },
    {
      "type": "action",
      "action": "for_each",
      "items": "$llm.selected",
      "variable": "answer",
      "do": {
        "type": "action",
        "action": "find_and_click",
        "params": {
          "target": "$answer",
          "role": "AXCheckBox",
          "strategy": "focus_space",
          "match_mode": "exact",
          "post_delay": 1.0
        }
      }
    },
    {
      "type": "action",
      "action": "wait_for_element",
      "params": {
        "role": "AXButton",
        "target": "Check",
        "max_wait": 3.0
      }
    },
    {
      "type": "action",
      "action": "find_and_click",
      "params": {
        "target": "Check",
        "role": "AXButton",
        "strategy": "mouse_click",
        "match_mode": "exact",
        "post_delay": 2.5
      }
    },
    {
      "type": "action",
      "action": "store_qa",
      "params": {
        "question": "$q.question_text",
        "answer": "$llm.selected",
        "question_type": "solve_complex"
      }
    }
  ]
}
```
